{"path":"/data/projects/emmy/packages/emmy-provider/src/before-request-hook.ts","binary":false,"lines":"f4fccf41  // packages/emmy-provider/src/before-request-hook.ts
a2c23396  //
957442c8  // Plan 03-01 Task 2 (GREEN) — the pi 0.68 `before_provider_request`
98e972d4  // payload mutator. One concentrated place for the five live injections
f367dc20  // that Phase 3 Track B makes authoritative on every wire request:
a2c23396  //
107bfd1f  //   (a) D-02a: chat_template_kwargs.enable_thinking:false at request level
2f10297e  //       — this is the PROPER fix that obsoletes the a17f4a9 `<think>`-strip
99c450a4  //       stopgap. vLLM's Qwen3.6 chat template reads enable_thinking and
fc8919a8  //       generates NO `<think>` prefix when it's false.
a2c23396  //
9082f1c9  //   (b) D-02b: reactive grammar injection — when the retry-state for the
068e4ed8  //       request's AbortSignal says wantsGrammar=true (Phase 2 D-11 retry
edad8173  //       leg), this injects extra_body.guided_decoding.grammar_str from the
c5f34da3  //       profile's Lark file. Grammar config {path,mode} is the nested shape
85939b2a  //       (D-11 lock); mode="disabled" suppresses injection even on retry
678ec0dd  //       (Plan 02-08 SC-3 no-grammar baseline).
a2c23396  //
75acb813  //   (c) D-02c + D-04: the assembled 3-layer emmy prompt OVERWRITES pi's
e5aa1c63  //       templated system message at wire time. pi 0.68 builds its own
4867f587  //       system message from skills/resources; Emmy's prompt is the
c67e3d2b  //       CONTEXT-04 locked-order layering (system.md + AGENTS.md + tool_defs
73e50753  //       + user) whose SHA-256 is the HARNESS-06 audit identifier. The
427f1ca5  //       overwrite happens HERE — not at session boot — so every chat call
5d8e9b7e  //       on the live path carries the emmy-authoritative system prompt.
a2c23396  //
ad5b20c4  // SP_OK canary guard (RESEARCH Pitfall #7 / 03-CONTEXT T-03-01-02):
7e019a0f  //   If payload.emmy.is_sp_ok_canary === true, the hook is a pass-through.
a0e3993b  //   The canary fires BEFORE buildRealPiRuntime so this branch should never
db62291f  //   fire in practice — belt-and-suspenders against future wiring mistakes
b8bf0b32  //   that might route the canary through pi's stream.
e3b0c442  
7571c723  import { readFileSync } from "node:fs";
f84a38b0  import { join } from "node:path";
25b876df  import type { RetryState } from "./grammar-retry";
9a2839b6  import type { ProfileSnapshot, VariantSnapshot } from "./types";
e3b0c442  
dd30a96c  export type { RetryState };
e3b0c442  
06ca06b4  export interface BeforeProviderRequestPayload {
139f1edd  	model: string;
33cc29b5  	messages: Array<{ role: string; content: unknown }>;
d76af79c  	extra_body?: Record<string, unknown>;
0f11457c  	chat_template_kwargs?: Record<string, unknown>;
e4f56832  	// Phase 4 HARNESS-08 — variant-level sampling fields applied when a
1468f9ec  	// variantSnapshot is present. Their absence (undefined) means the wire
0656e1d4  	// layer or profile layer downstream is responsible for sampling
ea08df8b  	// defaults; presence is a per-turn override.
d42996ec  	temperature?: number;
f04fe480  	top_p?: number;
7ff010ce  	top_k?: number;
b770ed8d  	max_tokens?: number;
10fccfaf  	/**
fecf0d18  	 * Emmy-private payload namespace. Used today for the SP_OK canary
60e64dd5  	 * pass-through flag; future fields (turn_id correlation, trace context)
1df88522  	 * live here so they never collide with vLLM or OpenAI-standard fields.
f48539e2  	 */
1d8f6353  	emmy?: { is_sp_ok_canary?: boolean };
d10b36aa  }
e3b0c442  
2c6b4a45  export interface AssembledPromptSnapshot {
41fd265e  	text: string;
9a5abbeb  	sha256: string;
d10b36aa  }
e3b0c442  
3487ef8c  export function handleBeforeProviderRequest(args: {
a0739ee1  	payload: BeforeProviderRequestPayload;
552828f4  	profile: ProfileSnapshot;
ca261bed  	assembledPrompt: AssembledPromptSnapshot;
e349cc0c  	retryState: RetryState | null;
d94758c6  	// Phase 4 Plan 04-04 (HARNESS-08) — per-turn variant snapshot. When
d9d6e8c3  	// present, its harness.sampling_defaults / chat_template_kwargs override
bb239c04  	// the base profile's values. When absent (existing callers + Phase 3
edd4ba9b  	// wiring), the hook's behavior is unchanged.
c97d88f9  	variantSnapshot?: VariantSnapshot;
6d968387  }): void {
9bd5a50b  	const { payload, profile, assembledPrompt, retryState, variantSnapshot } = args;
e3b0c442  
9fd2df0d  	// SP_OK canary guard — never mutate the canary's payload. The canary runs
b84d50f9  	// BEFORE pi's extension runtime exists, so this branch is defensive only.
f3c17948  	if (payload.emmy?.is_sp_ok_canary === true) return;
e3b0c442  
ca5a7dd5  	// (pre) Plan 04-03 follow-up (2026-04-24): after /profile swap, pi's
dadac806  	// ModelRegistry still carries the boot-time served_model_name. vLLM
7ea6db3c  	// rejects with 404 ("model X does not exist") because the engine now
42548bca  	// answers under the NEW served_model_name. Overwrite payload.model with
aa06fb9b  	// the currently-loaded profile's served_model_name on every request —
5ac8ccf3  	// idempotent pre-swap (same string), corrective post-swap.
86da8f51  	payload.model = profile.serving.engine.served_model_name;
e3b0c442  
1cad510d  	// (a) D-02a: enable_thinking:false at request level. Removes a17f4a9.
7f76fa32  	payload.chat_template_kwargs = {
0fee95c1  		...(payload.chat_template_kwargs ?? {}),
b1d9dfd1  		enable_thinking: false,
d5130ff6  	};
e3b0c442  
159464a7  	// (a1) Phase 4 HARNESS-08 — variant snapshot application. Overrides the
283c9b6a  	// enable_thinking default (a) and the base profile sampling whenever a
162b1759  	// variant is active for the current turn. Tool-name + message-text based
2c5da2a5  	// role classification means temperature=0.6 on a "plan" turn and
d08481fd  	// temperature=0.0 on an "edit" turn, without restarting the vLLM engine
19bfc824  	// (serving.yaml is byte-identical across sibling variants per D-10).
7bb35d26  	if (variantSnapshot) {
4ec8aa61  		const sd = variantSnapshot.harness.sampling_defaults;
74bb68ff  		if (sd) {
cabf2dd8  			if (typeof sd.temperature === "number") payload.temperature = sd.temperature;
804ebff5  			if (typeof sd.top_p === "number") payload.top_p = sd.top_p;
c3b6c19e  			if (typeof sd.top_k === "number") payload.top_k = sd.top_k;
789364fa  			if (typeof sd.max_tokens === "number") payload.max_tokens = sd.max_tokens;
3713bbfd  		}
7d6beada  		if (variantSnapshot.harness.chat_template_kwargs) {
10fabcc7  			payload.chat_template_kwargs = {
8bbe574c  				...(payload.chat_template_kwargs ?? {}),
2ab016ff  				...variantSnapshot.harness.chat_template_kwargs,
ea5ef463  			};
3713bbfd  		}
32425a3c  		// Note: variant-specific system prompt mutation is deferred to the
d9b87aab  		// @emmy/ux caller; pi-emmy-extension.ts's before_provider_request
850a3820  		// handler rebuilds assembledPrompt.text when harness.prompts.system
a1777d96  		// points at a variant-specific file. This hook only applies the
fcf1228c  		// chat-request-shape fields directly.
a32a3bb7  	}
e3b0c442  
3d9fbe13  	// (b) D-02b: reactive grammar injection (Phase 2 D-11 live-path wiring).
421e8d5e  	if (retryState?.wantsGrammar === true) {
31c64a28  		const grammarCfg = profile.harness.tools.grammar;
725e668b  		if (grammarCfg !== null && grammarCfg.mode !== "disabled") {
16d8a3c9  			const grammarText = readFileSync(
85fd2760  				join(profile.ref.path, grammarCfg.path),
6a45000e  				"utf8",
cdf704fc  			);
9c960f81  			payload.extra_body = {
5ea79770  				...(payload.extra_body ?? {}),
cec6e89c  				guided_decoding: { grammar_str: grammarText },
ea5ef463  			};
3713bbfd  		}
a32a3bb7  	}
e3b0c442  
dc480f40  	// (c) D-02c + D-04: replace the system message with emmy's 3-layer prompt.
226a6259  	const idx = payload.messages.findIndex((m) => m.role === "system");
b174cf2f  	if (idx >= 0) {
ac14c975  		payload.messages[idx] = { role: "system", content: assembledPrompt.text };
ad65360e  	} else {
59e2b4cc  		payload.messages.unshift({ role: "system", content: assembledPrompt.text });
a32a3bb7  	}
d10b36aa  }
