9b4b8c14  export async function postChat(
3fc75565  	baseUrl: string,
93cd6f2b  	payload: ChatRequest,
db18feff  	opts: { timeoutMs?: number } = {},
f7bbd09b  ): Promise<ChatResponse> {
eb45b7fc  	const url = `${baseUrl.replace(/\/$/, "")}/v1/chat/completions`;
9d583544  	const timeoutMs = opts.timeoutMs ?? 120_000;
99ca39aa  	const controller = new AbortController();
8f9a52ee  	const timer = setTimeout(() => {
ce1d447b  		// AbortController.abort(reason) exists on modern runtimes; fall back gracefully.
131bbee0  		try {
66455ff5  			(controller as AbortController & { abort: (reason?: unknown) => void }).abort(
e2d0e426  				new Error("timeout"),
cdf704fc  			);
3dbe4bd7  		} catch (_e) {
346c162f  			controller.abort();
3713bbfd  		}
b8aa8589  	}, timeoutMs);
